{
  "shots": [
    {
      "shot_id": "SH01",
      "priority": "P0",
      "intent": "建立事件第四天午后的客厅遗物整理空间，让健一与彩花旧手袋、浅蓝丝巾、化妆品盒形成安静的寻找线索起点。",
      "duration_sec": 4,
      "shot_type": "中景",
      "movement": "固定机位，允许极轻微稳定推近",
      "framing_focus": "首帧是午后客厅地板上，田中健一坐在深棕色旧手袋前，浅蓝丝巾和米白色银边化妆品盒位于他膝前。",
      "action_intent": "健一低头看着膝前遗物，右手缓慢停在浅蓝丝巾和化妆品盒之间，只完成建立空间与遗物关系的单一任务。",
      "emotion_intent": "安静、疲惫、怀念中带着寻找线索前的压抑。",
      "scene_id": "EP06_LIVING_ROOM_RELIC_SORTING",
      "scene_name": "午后客厅遗物整理",
      "dialogue": [],
      "narration": [],
      "subtitle": [],
      "positive_core": "单一稳定首帧：事件第四天午后的客厅，纱帘后的柔和阳光落在地板上，田中健一穿疲惫西装、领带略松，坐在画面中下部，深棕色旧手袋开口朝上放在他膝前，浅蓝丝巾半铺在左侧，米白色银边化妆品盒闭合在右侧。竖屏9:16，低饱和写实电影感，真实光影，固定机位；健一低头凝视遗物，右手以很小幅度靠近，最后停在丝巾和化妆品盒之间。人物衣着完整，保持日常社交距离，朴素克制呈现；客厅安静，淡雅香水感以静物氛围和柔光表达。",
      "first_frame_contract": {
        "location": "事件第四天午后的健一客厅地板区域",
        "visual_center": "田中健一膝前的彩花旧手袋、浅蓝丝巾、化妆品盒与健一低头的上半身",
        "visible_characters": [
          "田中健一"
        ],
        "character_positions": {
          "田中健一": "画面中下部偏右，坐在客厅地板上，面向膝前遗物，低头保持稳定姿态"
        },
        "key_props": [
          "AYAKA_OLD_HANDBAG_01",
          "AYAKA_LIGHT_BLUE_SILK_SCARF_01",
          "AYAKA_COSMETIC_BOX_01"
        ],
        "speaking_state": "全程安静；田中健一保持沉默；远端声音不存在",
        "camera_motion_allowed": "固定机位，允许极轻微稳定推近"
      },
      "dialogue_blocking": {
        "active_speaker": "none",
        "first_speaker": "none",
        "speaker_visual_priority": "prop_closeup",
        "silent_visible_characters": [
          "田中健一"
        ],
        "lip_sync_policy": "no_dialogue"
      },
      "i2v_contract": {
        "shot_task": "establishing",
        "risk_level": "low",
        "risk_notes": "单人、单一地点、无对白、无电话，动作仅为手部微停，三件关键道具首帧稳定可见。",
        "prop_library": {
          "AYAKA_OLD_HANDBAG_01": {
            "display_name": "彩花旧手袋",
            "count": "1个",
            "size": "约30厘米 × 22厘米 × 12厘米",
            "color": "深棕色",
            "material": "旧皮革，表面有使用痕迹",
            "structure": "单肩手袋，顶部拉链打开，内里为深色布衬",
            "canonical_motion_policy": "默认放在客厅地板健一膝前，开口朝上；只允许被健一轻微拉近或从中取物。"
          },
          "AYAKA_LIGHT_BLUE_SILK_SCARF_01": {
            "display_name": "浅蓝丝巾",
            "count": "1条",
            "size": "约150厘米 × 35厘米",
            "color": "浅蓝色，低饱和冷调",
            "material": "丝质，表面有柔和反光",
            "structure": "长方形薄丝巾，边缘有细窄卷边",
            "canonical_motion_policy": "默认折叠或半铺在健一膝前；只允许由健一或美咲手部触碰、捏紧、放下或滑落。"
          },
          "AYAKA_COSMETIC_BOX_01": {
            "display_name": "彩花化妆品盒",
            "count": "1个",
            "size": "约14厘米 × 9厘米 × 5厘米",
            "color": "米白色外壳，银色边框",
            "material": "硬质塑料外壳，金属铰链，内部有镜面和细粉质化妆品格",
            "structure": "翻盖式小盒，盒盖可打开，内部镜面固定在盖内侧",
            "canonical_motion_policy": "默认闭合放置；需要展示时可由美咲递给健一或停在地板上，不做复杂开合。"
          }
        },
        "prop_contract": [
          {
            "prop_id": "AYAKA_OLD_HANDBAG_01",
            "position": "客厅地板上，田中健一膝前约20厘米，画面下部中央，顶部拉链打开，开口朝上",
            "first_frame_visible": true,
            "motion_policy": "本镜头保持原位静止，只允许健一手部靠近袋口附近，不取物",
            "controlled_by": "none"
          },
          {
            "prop_id": "AYAKA_LIGHT_BLUE_SILK_SCARF_01",
            "position": "田中健一膝前左侧，半铺在地板上，浅蓝色丝面可见",
            "first_frame_visible": true,
            "motion_policy": "本镜头保持半铺状态，末尾允许健一指尖轻触边缘但不改变整体位置",
            "controlled_by": "田中健一"
          },
          {
            "prop_id": "AYAKA_COSMETIC_BOX_01",
            "position": "田中健一膝前右侧，闭合放在地板上，米白色外壳和银色边框朝向镜头",
            "first_frame_visible": true,
            "motion_policy": "本镜头保持闭合静止，不开合、不递送",
            "controlled_by": "none"
          }
        ],
        "phone_contract": {
          "holder": "none",
          "screen_orientation": "not_applicable",
          "screen_content_visible": false
        }
      },
      "source_basis": "事件第四天午后，阳光从客厅纱帘后渗入；田中健一独自坐在地板上整理佐藤彩花的私物，旧手袋敞开，丝巾和化妆品盒摆在膝前。"
    }
  ],
  "qa_report": [
    {
      "check": "I2V rule self-check",
      "result": "pass",
      "notes": "只生成SH01一个镜头；镜头任务为establishing；单人可见、无对白、无电话回复、无多地点或时间跳转。"
    },
    {
      "check": "TARGET_FACTS alignment",
      "result": "pass",
      "notes": "包含事件第四天午后、健一独坐客厅地板、旧手袋打开、浅蓝丝巾与化妆品盒在膝前、手停在两件遗物之间。"
    },
    {
      "check": "prop consistency",
      "result": "pass",
      "notes": "三件关键道具均使用指定prop_id，并按道具目录定义数量、尺寸、颜色、材质、结构和运动策略。"
    },
    {
      "check": "first frame stability",
      "result": "pass",
      "notes": "首帧为单一客厅稳定画面，视觉中心明确，人物与道具位置固定，后续仅有微小手部动作。"
    }
  ]
}
